import type { EvidenceLevel } from "@/lib/types";

// ─── Profile type ─────────────────────────────────────────────────────────────
// Lighter than IngredientEntry — enough to power both the hub listing and
// the [slug] template article page for any ingredient without its own static route.

export interface IngredientProfile {
  // Hub-page fields (all required)
  slug: string;
  name: string;
  figure: string;          // "ING-001"
  category: string;
  evidence: EvidenceLevel;
  dose: string;            // e.g. "3–5g / day"
  mechanism: string;       // one-line for hub card
  bestFor: string[];       // 2–4 tags
  summary: string;         // 1–2 sentences for hub card

  // Article template fields
  aka?: string[];          // alternate names / trade names
  intro: string;           // 2–3 sentences for article lead
  mechanismDetail: string; // paragraph for "How It Works" section
  keyBenefits: {
    claim: string;
    evidence: EvidenceLevel;
    note: string;          // brief citation or context
  }[];
  dosageNotes: string;     // dosage guidance paragraph
  safetyNotes: string;     // safety / side-effect paragraph
  whoFor: string;          // "Best for X; less useful for Y"
  relatedSlugs?: string[]; // slugs of related ingredient pages
}

